-- Raw materials import from Item List.xlsx (Item Type = 'Raw material')
-- 1558 rows. Source is a pure item master (Tally export) — it carries no
-- operational/stock data (current_stock, reorder_point, lead_time_days,
-- approved_suppliers, unit_cost, moq, storage_class). All of these are set to
-- 0/NULL here and must be backfilled from a stock/procurement source later.
-- category = Parent Name from the source (a real, populated field).
-- tags = ["Unit: <Default Base Unit>"] where known, e.g. "Unit: Sqf".
-- status = 'active' (raw_materials.status is free text, not rendered as a
-- colored badge anywhere in the UI — the workspace derives low-stock badges
-- from current_stock vs reorder_point instead, so this default is not misleading).

insert into raw_materials
  (id, code, name, category, status, category_owner, current_stock, reorder_point,
   lead_time_days, approved_suppliers, compatible_substrates, unit_cost, moq,
   storage_class, tags, created_at)
